-- P3 Materials (M1) — datasheet-backed material TYPE catalog (admin-editable reference table).
--
-- The controlled vocabulary of material TYPES a job's Material List draws from (manifest model,
-- M2). A PLAIN reference table (NOT integrity-bar): admin create INSERTs, edit UPDATEs in place,
-- retire is a SOFT-delete (active=0) so receipts/incidents that reference a catalog_id keep their
-- target. Seeded with the 36 operator-APPROVED types (field_ops/data/material_catalog_draft.json,
-- auto-extracted + deduped from project datasheets); near-variants (e.g. 480/600/800V) stay
-- DISTINCT rows. `unit_cost` is an OPTIONAL reference price (NULLABLE) — the authoritative
-- monetary value comes from the per-job Material List line (M2), never from here.
--
-- Capabilities: cap.materials.manage (admin, catalog CRUD) + cap.materials.receive
-- (submitter+admin, read to pick a type) are ALREADY seeded in 0013 — NOT re-seeded here.
--
-- ORDER DEPENDENCY (activation): apply BEFORE the Worker that reads/writes material_catalog
-- deploys (fieldops_material_write.ts / fieldops_materials.ts bind these columns). Mirrors the
-- 0013/0015/0016 activation rule.

CREATE TABLE IF NOT EXISTS material_catalog (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  model_id     TEXT    NOT NULL,                       -- product/model identifier (display + dedupe)
  manufacturer TEXT,                                   -- maker (may be 'Generic')
  category     TEXT    NOT NULL,                       -- module | inverter | tracker | switchgear | ...
  key_specs    TEXT,                                   -- short free-text spec summary
  source_files TEXT,                                   -- JSON array of source datasheet filenames (provenance)
  unit_cost    REAL,                                   -- OPTIONAL reference unit cost (NULL = unset; value lives on the Material List line)
  active       INTEGER NOT NULL DEFAULT 1,             -- 1 = live, 0 = soft-retired (never hard-delete)
  created_at   INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at   INTEGER NOT NULL DEFAULT (unixepoch())
);
CREATE INDEX IF NOT EXISTS idx_material_catalog_active ON material_catalog(active, category);

-- Seed the 36 approved types (source_files retained as JSON provenance; unit_cost left NULL).
